insert into tasks (id, project_id, package_id, title, description, status, priority, owner, assignee, workstream, sort_order, start_date, end_date, deadline, estimate_hours, definition_of_done, evidence_link, issue_number, issue_url, watched) values ('youssef-englische-klinik-setter-outreach-welle-starten', 'findmydoc-founder-execution', 'GC2', 'Englische Klinik-Setter-Outreach-Welle starten', 'Youssef kontaktiert anhand der von Sebastian gelieferten und von Anil bereinigten Bookimed-/Grey-Prospect-Liste 30 Kliniken auf Englisch per Telefon und/oder E-Mail. Ziel ist nicht direktes Closing, sondern qualifizierte Termine für Volkan, Anil oder Özen vorzubereiten, damit diese Kliniken closen, pilotieren oder onboarden können.', 'Offen', 'P1', 'youssef', 'youssef', 'Klinikpipeline', 2, '2026-06-22', '2026-06-24', 'Sprint 1', 4, '30 priorisierte Kliniken wurden englisch kontaktiert oder alle verfügbaren, falls weniger als 30 sauber freigegeben sind; jede Aktivität ist im vereinbarten CRM/Pipeline-System dokumentiert; qualifizierte Rückmeldungen haben Owner, nächsten Schritt und Terminvorschlag.', 'CRM-/Pipeline-View, Aktivitätsliste oder Versand-/Call-Nachweise der 30 kontaktierten Kliniken nach Fertigstellung.', null, null, false) on conflict (id) do update set package_id = excluded.package_id, title = excluded.title, description = excluded.description, status = excluded.status, priority = excluded.priority, owner = excluded.owner, assignee = excluded.assignee, workstream = excluded.workstream, sort_order = excluded.sort_order, start_date = excluded.start_date, end_date = excluded.end_date, deadline = excluded.deadline, estimate_hours = excluded.estimate_hours, definition_of_done = excluded.definition_of_done, evidence_link = excluded.evidence_link, issue_number = excluded.issue_number, issue_url = excluded.issue_url, watched = excluded.watched;

